# EMBOPSA_V0003F
# Eight-planet daily-cadence video with embedded user-supplied galaxy background.
# Deterministic scientific graphics only. No AI-generated imagery.

from __future__ import annotations
import base64, requests

VERSION = "V0003F"
BASE_URL = (
    "https://raw.githubusercontent.com/gear66me-ui/"
    "JPL_EARTH_ORBITAL_PRECESSION_FFT/"
    "9668e61204321bd4aca4c2300aec0568656cc9ef/EMBOPSA_V0003E.py"
)
GALAXY_JPEG_B64 = '[... content omitted in source message for brevity ...]'

r = requests.get(BASE_URL, timeout=300)
r.raise_for_status()
source = r.text

patches = [
    ('VERSION = "V0003E"', 'VERSION = "V0003F"'),
    ('TEMP_AVI = OUT_DIR / "EMBOPSA_TEMP_EIGHT_PLANETS_DAILY_10Y.avi"', 'TEMP_AVI = OUT_DIR / "EMBOPSA_TEMP_EIGHT_PLANETS_DAILY_10Y_GALAXY_BG.avi"'),
    ('OUT_MP4 = OUT_DIR / "EMBOPSA_EIGHT_PLANETS_DAILY_2016_2026_H264.mp4"', 'OUT_MP4 = OUT_DIR / "EMBOPSA_EIGHT_PLANETS_DAILY_2016_2026_GALAXY_BG_H264.mp4"'),
    ('import cv2\nimport numpy as np', 'import cv2\nimport numpy as np\nimport base64'),
]
for old, new in patches:
    if old not in source:
        raise RuntimeError(f"Required source token not found: {old}")
    source = source.replace(old, new, 1)

insert = '\n_bg_bytes = base64.b64decode(GALAXY_JPEG_B64)\n_bg_array = np.frombuffer(_bg_bytes, dtype=np.uint8)\nbackground = cv2.imdecode(_bg_array, cv2.IMREAD_COLOR)\nif background is None:\n    raise RuntimeError("Embedded galaxy background could not be decoded.")\nbackground = cv2.resize(background, (WIDTH, HEIGHT), interpolation=cv2.INTER_CUBIC)\n'
marker = 'font = cv2.FONT_HERSHEY_SIMPLEX\n'
if marker not in source:
    raise RuntimeError("Background insertion point not found.")
source = source.replace(marker, marker + insert, 1)

old_frame = '        frame = np.zeros((HEIGHT, WIDTH, 3), dtype=np.uint8)\n'
if old_frame not in source:
    raise RuntimeError("Frame background token not found.")
source = source.replace(old_frame, '        frame = background.copy()\n', 1)

old_title = '        cv2.putText(frame, "Eight-Planet Motion — Daily Cadence", (320, 38), font, 0.95,\n                    (255, 255, 255), 2, cv2.LINE_AA)'
new_title = '        overlay = frame.copy()\n        cv2.rectangle(overlay, (0, 0), (WIDTH, 74), (0, 0, 0), -1)\n        cv2.addWeighted(overlay, 0.74, frame, 0.26, 0, frame)\n        cv2.putText(frame, "Eight-Planet Motion — Daily Cadence", (320, 38), font, 0.95,\n                    (255, 255, 255), 2, cv2.LINE_AA)'
if old_title not in source:
    raise RuntimeError("Title patch token not found.")
source = source.replace(old_title, new_title, 1)

old_date = '        date_label = current_date.strftime("%Y-%m-%d")'
new_date = '        footer = frame.copy()\n        cv2.rectangle(footer, (0, HEIGHT - 62), (WIDTH, HEIGHT), (0, 0, 0), -1)\n        cv2.addWeighted(footer, 0.76, frame, 0.24, 0, frame)\n        date_label = current_date.strftime("%Y-%m-%d")'
if old_date not in source:
    raise RuntimeError("Footer patch token not found.")
source = source.replace(old_date, new_date, 1)

source = source.replace('print(f"\\nSaved: {OUT_MP4}")', 'print(f"\\nSaved: {OUT_MP4} | Embedded galaxy background: user-supplied image, left crop")', 1)

for token in ['frame = background.copy()', 'GALAXY_BG_H264.mp4', 'Embedded galaxy background']:
    if token not in source:
        raise RuntimeError(f"Final verification failed; missing: {token}")

exec(compile(source, "EMBOPSA_V0003F_GENERATED.py", "exec"), globals(), globals())
